<template>
  <!-- 左侧分类导航 -->
  <div class="sidebar">
    <el-menu :default-active="String(currentCategory)" mode="horizontal" background-color="#545c64" active-text-color="cyan">
      <el-menu-item v-if="collectionStatus" index="-1" @click="collectionClick()">
        <span slot="title">我的收藏</span>
      </el-menu-item>
      <customer-menu-item v-for="item in finalCategoryList" :key="item.id" :item="item" :depth="2" @select="handleSelect" />
    </el-menu>
  </div>
</template>

<script>
import CustomerMenuItem from '@/components/CustomerMenuItem.vue';

export default {
  name: 'SlideLeftTwo',
  components: { CustomerMenuItem },
  props: {
    categoryList: {
      type: Array,
      default: () => []
    },
    collectionStatus: {
      type: Boolean,
      default: false
    },
    lasterVersion: {
      type: String,
      default: null
    },
    currentVersion: {
      type: String,
      default: null
    }
  },
  data() {
    return {
      finalCategoryList: [],
      currentCategory: '-1', // 默认选中收藏
      currentCategoryParent: null,
      queryParams: {
        firstCategoryId: null,
        categoryId: null,
        thirdCategoryId: null,
        fourCategoryId: null
      }
    };
  },
  watch: {
    lasterVersion: 'checkAndFilter',
    currentVersion: 'checkAndFilter',
    categoryList: {
      handler: 'checkAndFilter',
      immediate: true
    }
  },
  methods: {
    collectionClick() {
      this.currentCategory = '-1'; // 设置当前分类为收藏
      this.$emit('handleCollectionList', null); // 通知父组件刷新用户信息
    },
    checkAndFilter() {
      // 先从原始列表复制，再过滤
      if (this.lasterVersion && this.currentVersion && this.lasterVersion === this.currentVersion) {
        this.finalCategoryList = this.categoryList.filter((item) => !item.nameCn.includes('更新提示'));
      } else {
        this.finalCategoryList = this.categoryList;
      }
      if (this.collectionStatus) {
        this.collectionClick();
      } else if (this.finalCategoryList.length > 0) {
        this.handleSelect({ id: this.finalCategoryList[0].id, depth: 2 });
      }
    },
    async handleQuery() {
      this.$emit('handleParams', this.queryParams);
    },
    async handleSelect({ id, depth }) {
      this.currentCategory = id;
      // 根据层级赋值对应的 queryParams，并清空其他层级
      this.queryParams = {
        firstCategoryId: depth === 1 ? id : null,
        categoryId: depth === 2 ? id : null,
        thirdCategoryId: depth === 3 ? id : null,
        fourCategoryId: depth === 4 ? id : null
      };
      await this.handleQuery();
    }
  }
};
</script>

<style scoped>
.sidebar {
  height: 100%;
}

.sidebar .el-menu {
  height: 100%;
  overflow-x: hidden;
  overflow-y: auto;
}
.el-menu-item {
  color: white !important;
  width: 100%;
  align-items: center;
}

/* 一级标题间距大小调整 */
.el-menu-item,
.el-submenu__title {
  height: 30px !important;
  line-height: 30px !important;
}
</style>
